import (
	context "context"
	fern "github.com/null-type/fern"
	fernclient "github.com/null-type/fern/client"
)

client := fernclient.NewClient()
response, err := client.Conversations.OutboundCall(
	context.TODO(),
	&fern.OutboundCallConversationsRequest{
		ToPhoneNumber: "to_phone_number",
	},
)

